1	/**
2	 * AI外贸顾问系统 — 每日一键巡检
3	 * 用法: node daily-pipeline.mjs
4	 * 前置: Chrome 9222已开，小满TM页面已登录
5	 *
6	 * 流程: 全量提取 → 分类 → P0/P1深抓 → 战报输出
7	 */
8	
9	import { execSync } from 'child_process';
10	import { join, dirname } from 'path';
11	import { fileURLToPath } from 'url';
12	
13	const __dirname = dirname(fileURLToPath(import.meta.url));
14	
15	function run(scriptName, label) {
16	  console.log(`\n${'='.repeat(50)}`);
17	  console.log(`  ${label}`);
18	  console.log(`${'='.repeat(50)}`);
19	  try {
20	    execSync(`node "${join(__dirname, scriptName)}"`, {
21	      stdio: 'inherit',
22	      timeout: 600000, // 10 min max
23	    });
24	    console.log(`✅ ${label} 完成`);
25	    return true;
26	  } catch (e) {
27	    console.error(`❌ ${label} 失败: ${e.message}`);
28	    return false;
29	  }
30	}
31	
32	async function main() {
33	  console.log('╔══════════════════════════════════════╗');
34	  console.log('║  AI外贸顾问 — 每日巡检管线            ║');
35	  console.log('║  ' + new Date().toISOString() + '        ║');
36	  console.log('╚══════════════════════════════════════╝');
37	
38	  const startTime = Date.now();
39	
40	  // Phase 1: 全量提取+分类
41	  const p1 = run('extract-all-v2.mjs', 'Phase 1: 全量客户提取+分类');
42	
43	  // Phase 2: P0/P1深抓
44	  let p2 = false;
45	  if (p1) {
46	    p2 = run('deep-scrape-p0p1.mjs', 'Phase 2: P0/P1深抓对话');
47	  }
48	
49	  // Phase 3: 生成战报（由CC执行分析）
50	  const elapsed = ((Date.now() - startTime) / 1000).toFixed(0);
51	  console.log(`\n🏁 管线完成 (${elapsed}s)`);
52	  console.log(`   Phase 1 (提取分类): ${p1 ? '✅' : '❌'}`);
53	  console.log(`   Phase 2 (P0/P1深抓): ${p2 ? '✅' : '❌'}`);
54	  console.log(`\n📋 下一步: 将data目录最新JSON + reports模板 → 发给CC做五步分析`);
55	}
56	
57	main().catch(err => {
58	  console.error('管线错误:', err.message);
59	  process.exit(1);
60	});
