1	/**
2	 * OKKI 每日客户分析一键流水线
3	 *
4	 * 用法：
5	 *   node scripts/daily_pipeline.js           完整流程
6	 *   node scripts/daily_pipeline.js --no-ai   跳过AI话术
7	 *   node scripts/daily_pipeline.js --p0-only 只看P0客户
8	 *
9	 * 输入：
10	 *   data/tm_conversations_latest.json — 全量466客户元数据（由sync_okki.js产出）
11	 *   data/s1_enhanced.json          — 44活跃客户的增强特征（由enhanced_classify.js产出）
12	 * 输出：
13	 *   output/daily_YYYY-MM-DD.xlsx   — Excel看板
14	 *   output/actions_YYYY-MM-DD.md   — 行动清单
15	 */
16	
17	const fs = require('fs');
18	const path = require('path');
19	const ExcelJS = require('exceljs');
20	
21	const DATA_DIR = path.join(__dirname, '..', 'data');
22	const CONFIG_DIR = path.join(__dirname, '..', 'config');
23	const OUTPUT_DIR = path.join(__dirname, '..', 'output');
24	
25	// 我方 OKKI UID（用于判断消息方向）
26	const OUR_UID = '2500000853693@icbu';
27	
28	// ===================== 工具函数 =====================
29	
30	function loadJSON(filepath) {
31	  if (!fs.existsSync(filepath)) {
32	    console.error(`[ERROR] 文件不存在: ${filepath}`);
33	    return null;
34	  }
35	  return JSON.parse(fs.readFileSync(filepath, 'utf-8'));
36	}
37	
38	function todayStr() {
39	  const now = new Date();
40	  const yyyy = now.getFullYear();
41	  const mm = String(now.getMonth() + 1).padStart(2, '0');
42	  const dd = String(now.getDate()).padStart(2, '0');
43	  return `${yyyy}-${mm}-${dd}`;
44	}
45	
46	function daysBetween(ts1, ts2) {
47	  return Math.floor((ts1 - ts2) / (1000 * 60 * 60 * 24));
48	}
49	
50	// ===================== 数据加载与合并 =====================
51	
52	/**
53	 * 从 tm_conversations_latest.json 加载全量客户元数据，
54	 * 与 s1_enhanced.json 的增强特征合并。
55	 * 返回统一的客户数组。
56	 */
57	function loadAndMergeCustomers() {
58	  // 1. 加载全量元数据
59	  const metaPath = path.join(DATA_DIR, 'tm_conversations_latest.json');
60	  if (!fs.existsSync(metaPath)) {
61	    console.error(`[ERROR] 元数据文件不存在: ${metaPath}`);
62	    console.error('[HINT] 请先运行 node scripts/sync_okki.js');
63	    process.exit(1);
64	  }
65	  const meta = loadJSON(metaPath);
66	  const convs = meta.conversations || [];
67	  const now = Date.now();
68	
69	  // 2. 加载增强特征
70	  let enhancedMap = {};
71	  const enhancedPath = path.join(DATA_DIR, 's1_enhanced_full.json');
72	  if (fs.existsSync(enhancedPath)) {
73	    const enhanced = loadJSON(enhancedPath);
74	    if (Array.isArray(enhanced)) {
75	      for (const e of enhanced) {
76	        if (e.cid) enhancedMap[e.cid] = e;
77	      }
78	      console.log(`[DATA] 增强特征: ${enhanced.length} 个客户`);
79	    }
80	  } else {
81	    console.log('[DATA] 无增强特征文件,仅使用元数据');
82	  }
83	
84	  // 3. 合并
85	  const customers = convs.map(conv => {
86	    const cid = conv.cid;
87	    const enhanced = enhancedMap[cid] || {};
88	
89	    // 从元数据提取
90	    const lastContactTime = conv.lastContactTime || conv.lastContactTimeLong || 0;
91	    const daysAgo = lastContactTime ? daysBetween(now, lastContactTime) : 999;
92	    const country = conv.complianceCountryCode || '';
93	    const name = conv.name || conv.companyName || conv.loginId || '(未知)';
94	    const tags = conv.tagInfo || [];
95	    const latestMsg = conv.latestMessage || {};
96	    const isLatestFromUs = latestMsg.messageType === 'send';
97	    const isLatestFromCust = latestMsg.messageType === 'received';
98	
99	    // 基础特征（优先用增强数据，否则从元数据推断）
100	    const hasPI = enhanced.hasPI || false;
101	    const hasAddress = enhanced.hasAddress || false;
102	    const hasOrderSignal = enhanced.hasOrderSignal || false;
103	    const hasPrice = enhanced.hasPrice || false;
104	    const hasSample = enhanced.hasSample || false;
105	    const hasFreight = enhanced.hasFreight || false;
106	    const hasMOQ = enhanced.hasMOQ || false;
107	    const hasQuantity = enhanced.hasQuantity || false;
108	    const msgCount = enhanced.msgCount || 0;
109	    const customerMsgs = enhanced.customerMsgs || 0;
110	    const ourMsgs = enhanced.ourMsgs || 0;
111	    const sysMsgs = enhanced.sysMsgs || 0;
112	    const realMsgs = enhanced.realMsgs || 0;
113	    const cRatio = enhanced.cRatio || 0;
114	    const lastCustomerMsgDays = enhanced.lastCustomerMsgDays !== undefined
115	      ? enhanced.lastCustomerMsgDays
116	      : (isLatestFromCust ? daysAgo : 999);
117	    const latestOurMsg = enhanced.latestOurMsg || (isLatestFromUs ? latestMsg.content : '');
118	    const latestCustMsg = enhanced.latestCustMsg || (isLatestFromCust ? latestMsg.content : '');
119	
120	    const isCore = tags.includes('3P4KK0L1O5A501H');
121	
122	    return {
123	      cid,
124	      name,
125	      country,
126	      isCore,
127	      daysAgo,
128	      msgCount,
129	      customerMsgs,
130	      ourMsgs,
131	      sysMsgs,
132	      realMsgs,
133	      cRatio,
134	      lastCustomerMsgDays,
135	      latestOurMsg,
136	      latestCustMsg,
137	      hasPI,
138	      hasAddress,
139	      hasOrderSignal,
140	      hasPrice,
141	      hasSample,
142	      hasFreight,
143	      hasMOQ,
144	      hasQuantity,
145	      _source: enhanced.cid ? 'enhanced' : 'metadata'
146	    };
147	  });
148	
149	  const enhancedCount = customers.filter(c => c._source === 'enhanced').length;
150	  console.log(`[DATA] 全量: ${customers.length} 个客户 (${enhancedCount} 有增强特征, ${customers.length - enhancedCount} 仅元数据)`);
151	  return customers;
152	}
153	
154	// ===================== 手动覆盖 =====================
155	
156	/**
157	 * 读取 config/overrides.csv（如果存在），返回 name→tier 的映射。
158	 * CSV 格式：客户名,梯队
159	 * 用 Excel/WPS 打开编辑即可。
160	 */
161	function loadOverrides() {
162	  const csvPath = path.join(CONFIG_DIR, 'overrides.csv');
163	  if (!fs.existsSync(csvPath)) return {};
164	
165	  const content = fs.readFileSync(csvPath, 'utf-8');
166	  const map = {};
167	  const lines = content.split(/\r?\n/).filter(l => l.trim());
168	  for (const line of lines) {
169	    const parts = line.split(',');
170	    if (parts.length >= 2) {
171	      const name = parts[0].trim();
172	      const tier = parts[1].trim().toLowerCase();
173	      if (name && ['p0', 'p1', 'p2', 'p3', 'p4'].includes(tier)) {
174	        map[name] = tier;
175	      }
176	    }
177	  }
178	  if (Object.keys(map).length > 0) {
179	    console.log(`[OVERRIDE] 手动覆盖: ${Object.keys(map).length} 个客户`);
180	  }
181	  return map;
182	}
183	
184	/**
185	 * 应用手动覆盖：用 CSV 中的梯队替换自动分类结果。
186	 */
187	function applyOverrides(customers, overrides, rules) {
188	  if (Object.keys(overrides).length === 0) return customers;
189	  let count = 0;
190	  return customers.map(c => {
191	    const override = overrides[c.name];
192	    if (override && override !== c.tier) {
193	      count++;
194	      const tierDef = rules[override];
195	      return {
196	        ...c,
197	        tier: override,
198	        tierLabel: tierDef ? tierDef.label : override.toUpperCase(),
199	        tierReason: '（手动覆盖）',
200	        score: c.score // 保持原分数，覆盖不影响排序
201	      };
202	    }
203	    return c;
204	  });
205	  if (count > 0) console.log(`[OVERRIDE] 实际覆盖: ${count} 人`);
206	}
207	
208	// ===================== 规则引擎 =====================
209	
210	function evalCondition(customer, cond) {
211	  const val = customer[cond.field];
212	  if (val === undefined) return false;
213	
214	  switch (cond.op) {
215	    case 'eq': return val === cond.value;
216	    case 'neq': return val !== cond.value;
217	    case 'gt': return val > cond.value;
218	    case 'gte': return val >= cond.value;
219	    case 'lt': return val < cond.value;
220	    case 'lte': return val <= cond.value;
221	    case 'in': return Array.isArray(cond.value) && cond.value.includes(val);
222	    case 'contains': return typeof val === 'string' && val.toLowerCase().includes(String(cond.value).toLowerCase());
223	    default: return false;
224	  }
225	}
226	
227	function matchRule(customer, rule) {
228	  if (rule.all) return rule.all.every(c => evalCondition(customer, c));
229	  if (rule.any) return rule.any.some(c => evalCondition(customer, c));
230	  return false;
231	}
232	
233	/**
234	 * 对单个客户做五梯队分类。
235	 * 按 P0→P1→P2→P3 顺序匹配，命中即停止。都未命中归入 P4。
236	 */
237	function classifyCustomer(customer, rules) {
238	  for (const tier of ['p0', 'p1', 'p2', 'p3']) {
239	    const tierDef = rules[tier];
240	    if (!tierDef || !tierDef.rules) continue;
241	    for (const rule of tierDef.rules) {
242	      if (matchRule(customer, rule)) {
243	        return { ...customer, tier, tierLabel: tierDef.label, tierReason: rule.name };
244	      }
245	    }
246	  }
247	  return { ...customer, tier: 'p4', tierLabel: rules.p4.label, tierReason: rules.p4.description };
248	}
249	
250	// ===================== 评分引擎 =====================
251	
252	const TIER_BASE = { p0: 100, p1: 70, p2: 45, p3: 20, p4: 0 };
253	
254	function scoreCustomer(customer, scoring, rules) {
255	  const w = scoring.weights;
256	  let score = TIER_BASE[customer.tier] || 0;
257	
258	  // 时效惩罚：每多1天扣分
259	  score -= (customer.daysAgo || 0) * w.daysAgo_penalty.value;
260	
261	  // 客户最近回复加分
262	  if (customer.lastCustomerMsgDays !== undefined && customer.lastCustomerMsgDays <= 1) {
263	    score += w.lastCustomerMsg_bonus.value;
264	  }
265	
266	  // 核心市场加分
267	  if (rules.core_markets.includes(customer.country)) {
268	    score += w.core_market_bonus.value;
269	  }
270	
271	  // 下单信号加分
272	  if (customer.hasOrderSignal) {
273	    score += w.order_signal_bonus.value;
274	  }
275	
276	  // PI+地址加分
277	  if (customer.hasPI && customer.hasAddress) {
278	    score += w.pi_address_bonus.value;
279	  }
280	
281	  // 高互动加分
282	  if (customer.realMsgs >= 30) {
283	    score += w.high_engagement_bonus.value;
284	  }
285	
286	  // 客户消息占比高加分
287	  if (customer.cRatio >= 40) {
288	    score += w.customer_reply_bonus.value;
289	  }
290	
291	  // 沉默惩罚
292	  const silence = rules.silence_warnings[customer.tier];
293	  if (silence && customer.lastCustomerMsgDays >= silence.danger) {
294	    score -= w.silence_penalty.value;
295	  }
296	
297	  return { ...customer, score };
298	}
299	
300	// ===================== 阶段判断 =====================
301	
302	function determineStage(customer) {
303	  if (customer.hasPI && customer.hasAddress && customer.daysAgo <= 7) {
304	    return { stage: 1, label: '待确认付款', action: '确认PI信息无误 → 提醒付款 → 锁定排产。时效：24h内。' };
305	  }
306	  if (customer.realMsgs >= 15 && customer.daysAgo <= 3) {
307	    return { stage: 2, label: '谈判中·近期活跃', action: '补全信息缺口 → 给价格区间 → 引导下一步。时效：48h内。' };
308	  }
309	  if (customer.hasPrice && customer.lastCustomerMsgDays >= 3) {
310	    return { stage: 3, label: '报价已发·等回应', action: '3-5天后温和跟进(确认收到+提供新价值)，不要催单。' };
311	  }
312	  if (customer.realMsgs < 10 && customer.daysAgo <= 2) {
313	    return { stage: 4, label: '初询阶段', action: '确认数量+目的地 → 给报价 → 引导选款。时效：24h内。' };
314	  }
315	  if (customer.realMsgs <= 5 && customer.lastCustomerMsgDays >= 3) {
316	    return { stage: 5, label: '模板提问后沉默', action: '换策略重联：给选择题而非开放式问题，给具体产品推荐。' };
317	  }
318	  return { stage: 6, label: '低意向/非采购', action: '不投入时间，标记待观察。' };
319	}
320	
321	// ===================== 沉默风险检测 =====================
322	
323	function checkSilence(customer, rules) {
324	  const silence = rules.silence_warnings[customer.tier];
325	  if (!silence) return 'normal';
326	  const d = customer.lastCustomerMsgDays;
327	  if (d === undefined || d >= 900) return 'normal'; // 未知/元数据默认值，不报警
328	  if (d >= silence.danger) return 'danger';
329	  if (d >= silence.warning) return 'warning';
330	  return 'normal';
331	}
332	
333	// ===================== Excel 生成 =====================
334	
335	async function generateExcel(customers, rules, today) {
336	  const wb = new ExcelJS.Workbook();
337	  const ws = wb.addWorksheet('客户看板');
338	
339	  const headers = [
340	    '优先级', '梯队', '客户名', '国家', '阶段', '距今天数',
341	    '消息总数', '客户消息', '我方消息', '客户占比',
342	    'PI', '地址', '下单信号', '报价', '样品', '运费',
343	    '最近我方消息', '最近客户消息', '分类理由', '行动建议', '沉默风险', '手动调整'
344	  ];
345	
346	  const headerRow = ws.addRow(headers);
347	  headerRow.font = { bold: true, color: { argb: 'FFFFFFFF' } };
348	  headerRow.fill = { type: 'pattern', pattern: 'solid', fgColor: { argb: 'FF2F5496' } };
349	  headerRow.alignment = { vertical: 'middle', horizontal: 'center' };
350	
351	  // 颜色定义
352	  const tierColors = {
353	    p0: { argb: 'FFFFC7CE' }, // 红色
354	    p1: { argb: 'FFFFEB9C' }, // 黄色
355	    p2: { argb: 'FFC6EFCE' }, // 绿色
356	    p3: { argb: 'FFBDD7EE' }, // 蓝色
357	    p4: { argb: 'FFD9D9D9' }  // 灰色
358	  };
359	  const silenceColors = {
360	    danger: { argb: 'FFFF4444' },
361	    warning: { argb: 'FFFFAA00' }
362	  };
363	
364	  for (const c of customers) {
365	    const stage = determineStage(c);
366	    const silence = checkSilence(c, rules);
367	
368	    const row = ws.addRow([
369	      c.score.toFixed(0),
370	      `${c.tier.toUpperCase()} - ${c.tierLabel}`,
371	      c.name || '(未知)',
372	      c.country || '',
373	      stage.label,
374	      c.daysAgo ?? '',
375	      c.msgCount ?? '',
376	      c.customerMsgs ?? '',
377	      c.ourMsgs ?? '',
378	      c.cRatio != null ? `${c.cRatio}%` : '',
379	      c.hasPI ? '✓' : '',
380	      c.hasAddress ? '✓' : '',
381	      c.hasOrderSignal ? '✓' : '',
382	      c.hasPrice ? '✓' : '',
383	      c.hasSample ? '✓' : '',
384	      c.hasFreight ? '✓' : '',
385	      (c.latestOurMsg || '').substring(0, 60),
386	      (c.latestCustMsg || '').substring(0, 60),
387	      c.tierReason || '',
388	      stage.action,
389	      silence === 'danger' ? '严重' : silence === 'warning' ? '注意' : '',
390	      c.tierReason === '（手动覆盖）' ? '已覆盖' : ''
391	    ]);
392	
393	    // 行着色
394	    const bg = tierColors[c.tier] || tierColors.p4;
395	    row.eachCell((cell, colNum) => {
396	      cell.fill = { type: 'pattern', pattern: 'solid', fgColor: bg };
397	      cell.alignment = { vertical: 'middle', wrapText: true };
398	    });
399	
400	    // 沉默风险着色
401	    if (silence === 'danger' || silence === 'warning') {
402	      const silenceCell = row.getCell(21);
403	      silenceCell.font = { bold: true, color: { argb: silence === 'danger' ? 'FFFF0000' : 'FFFF8800' } };
404	    }
405	  }
406	
407	  // 列宽
408	  ws.columns = headers.map((h, i) => {
409	    const widths = [7, 16, 20, 7, 16, 8, 7, 7, 7, 8, 5, 5, 7, 5, 5, 5, 40, 40, 28, 44, 7, 10];
410	    return { width: widths[i] || 12 };
411	  });
412	
413	  // 冻结首行
414	  ws.views = [{ state: 'frozen', ySplit: 1 }];
415	
416	  // 自动筛选
417	  ws.autoFilter = { from: 'A1', to: `V${customers.length + 1}` };
418	
419	  const outPath = path.join(OUTPUT_DIR, `daily_${today}.xlsx`);
420	  await wb.xlsx.writeFile(outPath);
421	  console.log(`[DONE] Excel 看板 → ${outPath}`);
422	  return outPath;
423	}
424	
425	// ===================== 行动清单生成 =====================
426	
427	function generateActionList(customers, rules, scoring, today) {
428	  const tiers = { p0: [], p1: [], p2: [], p3: [], p4: [] };
429	  for (const c of customers) {
430	    if (tiers[c.tier]) tiers[c.tier].push(c);
431	  }
432	
433	  let md = `# OKKI 每日行动清单 — ${today}\n\n`;
434	  md += `> 自动生成于 ${new Date().toLocaleString('zh-CN')}\n`;
435	  md += `> 客户总数：${customers.length} | `;
436	  md += `P0: ${tiers.p0.length} | P1: ${tiers.p1.length} | P2: ${tiers.p2.length} | P3: ${tiers.p3.length} | P4: ${tiers.p4.length}\n\n`;
437	
438	  md += `---\n\n## 统计概览\n\n`;
439	  md += `| 梯队 | 人数 | 说明 |\n`;
440	  md += `|------|------|------|\n`;
441	  md += `| P0 | ${tiers.p0.length} | ${rules.p0.description} |\n`;
442	  md += `| P1 | ${tiers.p1.length} | ${rules.p1.description} |\n`;
443	  md += `| P2 | ${tiers.p2.length} | ${rules.p2.description} |\n`;
444	  md += `| P3 | ${tiers.p3.length} | ${rules.p3.description} |\n`;
445	  md += `| P4 | ${tiers.p4.length} | ${rules.p4.description} |\n`;
446	
447	  // 沉默风险汇总
448	  const dangerList = customers.filter(c => checkSilence(c, rules) === 'danger');
449	  const warnList = customers.filter(c => checkSilence(c, rules) === 'warning');
450	  if (dangerList.length > 0 || warnList.length > 0) {
451	    md += `\n## 沉默风险预警\n\n`;
452	    if (dangerList.length > 0) {
