509	async function installLwp(cdpClient, iframeSessionId) {
510	  const expr = `
511	    (function() {
512	      var _send = WebSocket.prototype.send;
513	      var _ae = WebSocket.prototype.addEventListener;
514	
515	      window.__lwpPending = {};
516	      window.__lwpSeq = 0;
517	
518	      WebSocket.prototype.send = function(data) {
519	        if (!window.__lwpWs && this.readyState === 1) {
520	          window.__lwpWs = this;
521	          _ae.call(this, 'message', function(event) {
522	            try {
523	              var raw = typeof event.data === 'string' ? event.data : '';
524	              if (raw.indexOf('"code"') < 0) return;
525	              var parsed = JSON.parse(raw);
526	              var mid = parsed.headers && parsed.headers.mid;
527	              if (mid && window.__lwpPending[mid]) {
528	                var p = window.__lwpPending[mid];
529	                delete window.__lwpPending[mid];
530	                p.resolve(parsed);
531	              }
532	            } catch(e) {}
533	          });
534	          console.log('[LWP] WS captured: ' + this.url);
535	        }
536	        return _send.call(this, data);
537	      };
538	
539	      window.__lwpRequest = function(lwpPath, body) {
540	        return new Promise(function(resolve, reject) {
541	          var ws = window.__lwpWs;
542	          if (!ws || ws.readyState !== 1) { reject(new Error('WS not ready')); return; }
543	          var mid = Date.now() + ' ' + (++window.__lwpSeq);
544	          var req = JSON.stringify({ lwp: lwpPath, headers: { mid: mid }, body: body });
545	          window.__lwpPending[mid] = { resolve: resolve, reject: reject };
546	          ws.send(req);
547	          setTimeout(function() {
548	            if (window.__lwpPending[mid]) { delete window.__lwpPending[mid]; reject(new Error('timeout')); }
549	          }, 30000);
550	        });
551	      };
552	
553	      return JSON.stringify({ installed: true });
554	    })()
555	  `;
556	
557	  return sendToTarget(cdpClient, iframeSessionId, 3, expr);
558	}
