630	    const lct = c.lastContactTimeLong || c.lastContactTime || 0;
631	    c.preComputed.daysSinceLastContact = lct > 0 ? Math.floor((now - lct) / 86400000) : null;
632	
633	    // 3. latestMessage 是否是系统消息
634	    const lmContent = c.latestMessage?.content || '';
