196	function matchOrder(name, ordersData) {
197	  if (!ordersData || !ordersData.orders || ordersData.orders.length === 0) return null;
198	  if (!name) return null;
199	  const n = name.toLowerCase().trim();
200	  // 精确匹配
201	  for (const o of ordersData.orders) {
202	    if ((o.customer || '').toLowerCase().trim() === n) return { matched: true, status: o.status, paidAt: o.orderDate, orderNo: o.orderNo };
203	  }
204	  // 模糊匹配：客户名包含公司名或反之
205	  for (const o of ordersData.orders) {
206	    const cn = (o.customer || '').toLowerCase().trim();
207	    if (!cn) continue;
208	    if (n.includes(cn) || cn.includes(n)) return { matched: true, status: o.status, paidAt: o.orderDate, orderNo: o.orderNo };
209	  }
210	  return null;
211	}
